import os
import hashlib
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, session, request, redirect, url_for, render_template_string

app = Flask(__name__)
app.secret_key = os.urandom(24)
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(days=7)

users_db = {}
sessions_db = {}

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def create_user(username, password):
    if username in users_db:
        return False
    users_db[username] = {
        'password': hash_password(password),
        'created_at': datetime.now()
    }
    return True

def verify_user(username, password):
    if username not in users_db:
        return False
    return users_db[username]['password'] == hash_password(password)

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

def create_session(username):
    session.permanent = True
    session['user_id'] = username
    session['logged_in'] = True
    session['login_time'] = datetime.now().isoformat()
    sessions_db[username] = {
        'session_id': session.get('_id', ''),
        'login_time': datetime.now(),
        'last_activity': datetime.now()
    }

def destroy_session():
    username = session.get('user_id')
    if username and username in sessions_db:
        del sessions_db[username]
    session.clear()

def update_activity():
    username = session.get('user_id')
    if username and username in sessions_db:
        sessions_db[username]['last_activity'] = datetime.now()

@app.before_request
def before_request():
    if 'user_id' in session:
        update_activity()

@app.route('/')
def index():
    if 'user_id' in session:
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if not username or not password:
            return render_template_string(REGISTER_TEMPLATE, error='Username and password required')
        
        if create_user(username, password):
            return redirect(url_for('login'))
        else:
            return render_template_string(REGISTER_TEMPLATE, error='Username already exists')
    
    return render_template_string(REGISTER_TEMPLATE)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if 'user_id' in session:
        return redirect(url_for('dashboard'))
    
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if verify_user(username, password):
            create_session(username)
            return redirect(url_for('dashboard'))
        else:
            return render_template_string(LOGIN_TEMPLATE, error='Invalid credentials')
    
    return render_template_string(LOGIN_TEMPLATE)

@app.route('/dashboard')
@login_required
def dashboard():
    username = session.get('user_id')
    login_time = session.get('login_time')
    session_info = sessions_db.get(username, {})
    
    return render_template_string(DASHBOARD_TEMPLATE, 
                                 username=username,
                                 login_time=login_time,
                                 last_activity=session_info.get('last_activity'))

@app.route('/logout')
def logout():
    destroy_session()
    return redirect(url_for('login'))

